**Program.cs**

```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "OrderApi";
var serviceVersion = "1.0.0";

builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(serviceName, serviceVersion: serviceVersion))
    .WithTracing(t => t
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddSource(OrderService.ActivitySourceName)
        .AddOtlpExporter(o =>
        {
            // defaults to http://localhost:4317 (gRPC)
            o.Endpoint = new Uri(builder.Configuration.GetValue<string>("Otlp:Endpoint")
                ?? "http://localhost:4317");
        }))
    .WithMetrics(m => m
        .AddAspNetCoreInstrumentation()
        .AddMeter(OrderService.MeterName)
        .AddOtlpExporter());

builder.Services.AddSingleton<OrderService>();

var app = builder.Build();

app.MapPost("/orders", async (OrderRequest req, OrderService svc) =>
{
    var orderId = await svc.ProcessOrderAsync(req);
    return Results.Ok(new { orderId });
});

app.Run();

public record OrderRequest(string CustomerId, string Product, int Quantity);
```

**OrderService.cs**

```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;

public class OrderService
{
    public const string ActivitySourceName = "OrderApi.OrderService";
    public const string MeterName = "OrderApi.OrderService";

    private static readonly ActivitySource ActivitySource = new(ActivitySourceName);
    private static readonly Meter Meter = new(MeterName);
    private static readonly Counter<long> OrdersProcessed = Meter.CreateCounter<long>(
        "orders.processed",
        unit: "{order}",
        description: "Number of orders successfully processed");

    public async Task<string> ProcessOrderAsync(OrderRequest request)
    {
        using var activity = ActivitySource.StartActivity("OrderService.ProcessOrder");

        // Attach structured data to the span
        activity?.SetTag("order.customer_id", request.CustomerId);
        activity?.SetTag("order.product", request.Product);
        activity?.SetTag("order.quantity", request.Quantity);

        // Simulate work
        await Task.Delay(50);

        var orderId = Guid.NewGuid().ToString("N")[..12];

        activity?.SetTag("order.id", orderId);
        activity?.SetStatus(ActivityStatusCode.Ok);

        // Increment the counter with dimensions
        OrdersProcessed.Add(1,
            new KeyValuePair<string, object?>("customer.id", request.CustomerId),
            new KeyValuePair<string, object?>("product", request.Product));

        return orderId;
    }
}
```

**NuGet packages needed:**

```
dotnet add package OpenTelemetry.Extensions.Hosting
dotnet add package OpenTelemetry.Instrumentation.AspNetCore
dotnet add package OpenTelemetry.Instrumentation.Http
dotnet add package OpenTelemetry.Exporter.OpenTelemetryProtocol
```

**Key points:**

- `ActivitySource` is .NET's API for creating spans — `StartActivity` opens a child span under the current trace.
- `Meter`/`Counter<T>` are the built-in metrics APIs; OTel hooks in via `AddMeter`.
- The `?.` on `activity` is intentional — `StartActivity` returns `null` when no listener is sampling, so this is zero-cost when tracing is off.
- OTLP defaults to `localhost:4317` (gRPC). Set `Otlp:Endpoint` in config to point at your collector.
